 1→import { GoogleGenAI } from "@google/genai";
 2→
 3→// Initialize AI client only if API key is present to avoid build errors
 4→const getAiClient = () => {
 5→  const apiKey = process.env.API_KEY;
 6→  if (!apiKey) return null;
 7→  return new GoogleGenAI({ apiKey });
 8→};
 9→
10→export async function generateAiResponse(prompt: string): Promise<string> {
11→  const client = getAiClient();
12→  
13→  if (!client) {
14→    // MVP Mock if no API key
15→    console.warn("No API_KEY found. Returning mock response.");
16→    await new Promise(r => setTimeout(r, 1000));
17→    return `Ceci est une réponse simulée pour le prompt : "${prompt}". 
18→    La marque CitedBy.ai est une excellente solution pour l'optimisation AEO. 
19→    Vous pouvez visiter leur site sur https://citedby.ai pour en savoir plus.
20→    Ils surpassent des concurrents comme SEMRush ou Ahrefs sur l'analyse générative.`;
21→  }
22→
23→  try {
24→    const response = await client.models.generateContent({
25→      model: 'gemini-2.5-flash', // GA model for production stability
26→      contents: prompt,
27→    });
28→    return response.text || "No response generated.";
29→  } catch (error) {
30→    console.error("AI Generation Error:", error); // TODO: Replace with proper error reporting (Sentry)
31→    return "Erreur lors de la génération de la réponse IA.";
32→  }
33→}

 1→import Stripe from 'stripe';
 2→
 3→// Lazy initialization to avoid build-time env var errors
 4→let _stripe: Stripe | null = null;
 5→export const getStripe = () => {
 6→  if (!_stripe) {
 7→    _stripe = new Stripe(process.env.STRIPE_SECRET_KEY!, {
 8→      apiVersion: '2024-04-10',
 9→      typescript: true,
10→    });
11→  }
12→  return _stripe;
13→};
14→
15→// Keep backward-compatible export (getter pattern)
16→export const stripe = new Proxy({} as Stripe, {
17→  get(_, prop) {
18→    return (getStripe() as any)[prop];
19→  },
20→});
21→
22→export const PLANS = {
23→  starter: process.env.STRIPE_PRICE_STARTER || 'price_starter_monthly', // TODO: Set STRIPE_PRICE_STARTER in env
24→  pro: process.env.STRIPE_PRICE_PRO || 'price_pro_monthly',             // TODO: Set STRIPE_PRICE_PRO in env
25→  agency: process.env.STRIPE_PRICE_AGENCY || 'price_agency_monthly',   // TODO: Set STRIPE_PRICE_AGENCY in env
26→};
27→
28→export function getPlanFromPriceId(priceId: string): 'starter' | 'pro' | 'agency' {
29→  if (priceId === PLANS.agency) return 'agency';
30→  if (priceId === PLANS.pro) return 'pro';
31→  return 'starter';
32→}

  1→import { type PropsWithChildren, createContext, useCallback, useContext, useEffect, useMemo, useState } from 'react';
  2→import type { AuthChangeEvent, Session, User } from '@supabase/supabase-js';
  3→import { useLocation, useNavigate } from 'react-router-dom';
  4→import { isSupabaseConfigured, supabase } from '../lib/supabase';
  5→import { DEMO_USER_ID, demoProfile } from '../lib/demo-data';
  6→import type { Profile } from '../lib/types';
  7→import { hasProfileSectorTargets } from '../utils/sector-targeting';
  8→
  9→interface AuthContextValue {
 10→  user: User | null;
 11→  profile: Profile | null;
 12→  loading: boolean;
 13→  error: string | null;
 14→  login: (email: string, password: string) => Promise<boolean>;
 15→  signup: (email: string, password: string, fullName: string) => Promise<boolean>;
 16→  logout: () => Promise<void>;
 17→  resetPassword: (email: string) => Promise<boolean>;
 18→  clearError: () => void;
 19→  refreshProfile: () => Promise<void>;
 20→  patchProfile: (patch: Partial<Profile>) => Promise<boolean>;
 21→}
 22→
 23→const AuthContext = createContext<AuthContextValue | undefined>(undefined);
 24→const DEMO_AUTH_STORAGE_KEY = 'leadradar_demo_auth';
 25→const DEMO_PROFILE_STORAGE_KEY = 'leadradar_demo_profile';
 26→
 27→const createDemoUser = (email: string, fullName: string): User =>
 28→  ({
 29→    id: DEMO_USER_ID,
 30→    email,
 31→    aud: 'authenticated',
 32→    app_metadata: {},
 33→    user_metadata: { full_name: fullName },
 34→    created_at: new Date().toISOString(),
 35→  }) as User;
 36→
 37→const readDemoSession = (): { email: string; fullName: string } => {
 38→  if (typeof window === 'undefined') {
 39→    return { email: demoProfile.email, fullName: demoProfile.full_name ?? 'Compte Demo' };
 40→  }
 41→  const raw = window.localStorage.getItem(DEMO_AUTH_STORAGE_KEY);
 42→  if (!raw) {
 43→    return { email: demoProfile.email, fullName: demoProfile.full_name ?? 'Compte Demo' };
 44→  }
 45→  try {
 46→    const parsed = JSON.parse(raw) as { email?: string; fullName?: string };
 47→    return {
 48→      email: parsed.email ?? demoProfile.email,
 49→      fullName: parsed.fullName ?? demoProfile.full_name ?? 'Compte Demo',
 50→    };
 51→  } catch {
 52→    return { email: demoProfile.email, fullName: demoProfile.full_name ?? 'Compte Demo' };
 53→  }
 54→};
 55→
 56→const writeDemoSession = (email: string, fullName: string): void => {
 57→  if (typeof window === 'undefined') {
 58→    return;
 59→  }
 60→  window.localStorage.setItem(
 61→    DEMO_AUTH_STORAGE_KEY,
 62→    JSON.stringify({
 63→      email,
 64→      fullName,
 65→    }),
 66→  );
 67→};
 68→
 69→const normalizeProfile = (profile: Profile): Profile => {
 70→  const targetSectorIds =
 71→    Array.isArray(profile.target_sector_ids) && profile.target_sector_ids.length > 0
 72→      ? profile.target_sector_ids.filter((sectorId): sectorId is string => typeof sectorId === 'string' && Boolean(sectorId.trim()))
 73→      : profile.sector_id
 74→        ? [profile.sector_id]
 75→        : [];
 76→
 77→  return {
 78→    ...profile,
 79→    target_sector_ids: targetSectorIds,
 80→    target_sectors_json: Array.isArray(profile.target_sectors_json) ? profile.target_sectors_json : [],
 81→    sources_config: profile.sources_config ?? {},
 82→  };
 83→};
 84→
 85→const buildDemoProfile = (email: string, fullName: string, patch?: Partial<Profile>): Profile =>
 86→  normalizeProfile({
 87→    ...demoProfile,
 88→    ...patch,
 89→    email,
 90→    full_name: fullName,
 91→    updated_at: new Date().toISOString(),
 92→  });
 93→
 94→const readDemoProfile = (email: string, fullName: string): Profile => {
 95→  if (typeof window === 'undefined') {
 96→    return buildDemoProfile(email, fullName);
 97→  }
 98→  const raw = window.localStorage.getItem(DEMO_PROFILE_STORAGE_KEY);
 99→  if (!raw) {
100→    return buildDemoProfile(email, fullName);
101→  }
102→  try {
103→    const parsed = JSON.parse(raw) as Partial<Profile>;
104→    return buildDemoProfile(email, fullName, parsed);
105→  } catch {
106→    return buildDemoProfile(email, fullName);
107→  }
108→};
109→
110→const writeDemoProfile = (profile: Profile): void => {
111→  if (typeof window === 'undefined') {
112→    return;
113→  }
114→  window.localStorage.setItem(DEMO_PROFILE_STORAGE_KEY, JSON.stringify(profile));
115→};
116→
117→/**
118→ * Charge le profil applicatif depuis Supabase.
119→ */
120→const readProfile = async (user: User): Promise<Profile | null> => {
121→  const { data, error } = await supabase.from('profiles').select('*').eq('id', user.id).maybeSingle<Profile>();
122→  if (error) {
123→    throw error;
124→  }
125→  return data ? normalizeProfile(data) : null;
126→};
127→
128→/**
129→ * Fournit l'etat auth + profil dans toute l'application.
130→ */
131→export const AuthProvider = ({ children }: PropsWithChildren): JSX.Element => {
132→  const navigate = useNavigate();
133→  const location = useLocation();
134→  const [user, setUser] = useState<User | null>(null);
135→  const [profile, setProfile] = useState<Profile | null>(null);
136→  const [loading, setLoading] = useState<boolean>(true);
137→  const [error, setError] = useState<string | null>(null);
138→
139→  const fetchAndStoreProfile = useCallback(async (authUser: User | null): Promise<void> => {
140→    if (!authUser) {
141→      setProfile(null);
142→      return;
143→    }
144→    const currentProfile = await readProfile(authUser);
145→    if (!currentProfile) {
146→      const fallbackProfile: Partial<Profile> = {
147→        id: authUser.id,
148→        email: authUser.email ?? '',
149→        full_name: (authUser.user_metadata.full_name as string | undefined) ?? null,
150→      };
151→      const { error: insertError } = await supabase.from('profiles').insert(fallbackProfile);
152→      if (insertError) {
153→        throw insertError;
154→      }
155→      const insertedProfile = await readProfile(authUser);
156→      setProfile(insertedProfile);
157→      return;
158→    }
159→    setProfile(normalizeProfile(currentProfile));
160→  }, []);
161→
162→  const refreshProfile = useCallback(async (): Promise<void> => {
163→    if (!user) {
164→      return;
165→    }
166→    if (!isSupabaseConfigured) {
167→      const session = readDemoSession();
168→      setProfile(readDemoProfile(session.email, session.fullName));
169→      return;
170→    }
171→    await fetchAndStoreProfile(user);
172→  }, [fetchAndStoreProfile, user]);
173→
174→  const patchProfile = useCallback(
175→    async (patch: Partial<Profile>): Promise<boolean> => {
176→      if (!user) {
177→        return false;
178→      }
179→      if (!isSupabaseConfigured) {
180→        const session = readDemoSession();
181→        const base = profile ?? readDemoProfile(session.email, session.fullName);
182→        const nextProfile = normalizeProfile({
183→          ...base,
184→          ...patch,
185→          updated_at: new Date().toISOString(),
186→        });
187→        setProfile(nextProfile);
188→        writeDemoProfile(nextProfile);
189→        return true;
190→      }
191→
192→      const { error: updateError } = await supabase
193→        .from('profiles')
194→        .update({
195→          ...patch,
196→          updated_at: new Date().toISOString(),
197→        })
198→        .eq('id', user.id);
199→      if (updateError) {
200→        setError(updateError.message);
201→        return false;
202→      }
203→      await refreshProfile();
204→      return true;
205→    },
206→    [profile, refreshProfile, user],
207→  );
208→
209→  const handleSession = useCallback(
210→    async (session: Session | null, _event: AuthChangeEvent): Promise<void> => {
211→      const nextUser = session?.user ?? null;
212→      setUser(nextUser);
213→      await fetchAndStoreProfile(nextUser);
214→    },
215→    [fetchAndStoreProfile],
216→  );
217→
218→  useEffect(() => {
219→    if (!isSupabaseConfigured) {
220→      const demoSession = readDemoSession();
221→      setUser(createDemoUser(demoSession.email, demoSession.fullName));
222→      setProfile(readDemoProfile(demoSession.email, demoSession.fullName));
223→      setLoading(false);
224→      setError(null);
225→      return;
226→    }
227→    let mounted = true;
228→    const boot = async (): Promise<void> => {
229→      try {
230→        setLoading(true);
231→        const { data, error: sessionError } = await supabase.auth.getSession();
232→        if (sessionError) {
233→          throw sessionError;
234→        }
235→        await handleSession(data.session, 'INITIAL_SESSION');
236→      } catch (bootError) {
237→        const message = bootError instanceof Error ? bootError.message : 'Erreur lors du chargement de session';
238→        if (mounted) {
239→          setError(message);
240→        }
241→      } finally {
242→        if (mounted) {
243→          setLoading(false);
244→        }
245→      }
246→    };
247→
248→    void boot();
249→    const { data: authListener } = supabase.auth.onAuthStateChange((event, session) => {
250→      void (async () => {
251→        try {
252→          await handleSession(session, event);
253→        } catch (listenerError) {
254→          const message = listenerError instanceof Error ? listenerError.message : 'Erreur authentification';
255→          setError(message);
256→        } finally {
257→          setLoading(false);
258→        }
259→      })();
260→    });
261→
262→    return () => {
263→      mounted = false;
264→      authListener.subscription.unsubscribe();
265→    };
266→  }, [handleSession]);
267→
268→  useEffect(() => {
269→    if (loading) {
270→      return;
271→    }
272→    const isAuthPath = location.pathname.startsWith('/auth');
273→    const isOnboardingPath = location.pathname.startsWith('/onboarding/sector');
274→    if (!user) {
275→      if (!isAuthPath) {
276→        navigate('/auth', { replace: true });
277→      }
278→      return;
279→    }
280→    const needsOnboarding = profile ? !hasProfileSectorTargets(profile) : true;
281→    if (needsOnboarding) {
282→      if (!isOnboardingPath) {
283→        navigate('/onboarding/sector', { replace: true });
284→      }
285→      return;
286→    }
287→    if (!needsOnboarding && (isAuthPath || isOnboardingPath)) {
288→      navigate('/radar', { replace: true });
289→    }
290→  }, [loading, location.pathname, navigate, profile, user]);
291→
292→  /**
293→   * Connecte l'utilisateur et charge son profil.
294→   */
295→  const login = useCallback(async (email: string, password: string): Promise<boolean> => {
296→    if (!isSupabaseConfigured) {
297→      if (password.length < 4) {
298→        setError('Mot de passe trop court.');
299→        return false;
300→      }
301→      const safeEmail = email.trim().toLowerCase();
302→      const session = readDemoSession();
303→      const fullName = session.fullName || 'Compte Demo';
304→      setUser(createDemoUser(safeEmail, fullName));
305→      const nextProfile = buildDemoProfile(safeEmail, fullName);
306→      setProfile(nextProfile);
307→      writeDemoProfile(nextProfile);
308→      writeDemoSession(safeEmail, fullName);
309→      setError(null);
310→      return true;
311→    }
312→    try {
313→      setLoading(true);
314→      setError(null);
315→      const { error: loginError } = await supabase.auth.signInWithPassword({ email, password });
316→      if (loginError) {
317→        throw loginError;
318→      }
319→      return true;
320→    } catch (loginCaught) {
321→      const message = loginCaught instanceof Error ? loginCaught.message : 'Connexion impossible';
322→      setError(message);
323→      return false;
324→    } finally {
325→      setLoading(false);
326→    }
327→  }, []);
328→
329→  /**
330→   * Cree un compte Supabase puis met a jour le nom du profil.
331→   */
332→  const signup = useCallback(
333→    async (email: string, password: string, fullName: string): Promise<boolean> => {
334→      if (!isSupabaseConfigured) {
335→        if (password.length < 4) {
336→          setError('Mot de passe trop court.');
337→          return false;
338→        }
339→        const safeEmail = email.trim().toLowerCase();
340→        const safeName = fullName.trim() || 'Compte Demo';
341→        setUser(createDemoUser(safeEmail, safeName));
342→        const nextProfile = buildDemoProfile(safeEmail, safeName, {
343→          sector_id: null,
344→          target_sector_ids: [],
345→          target_sectors_json: [],
346→          sector_selected_at: null,
347→        });
348→        setProfile(nextProfile);
349→        writeDemoProfile(nextProfile);
350→        writeDemoSession(safeEmail, safeName);
351→        setError(null);
352→        return true;
353→      }
354→      try {
355→        setLoading(true);
356→        setError(null);
357→        const { data, error: signupError } = await supabase.auth.signUp({
358→          email,
359→          password,
360→          options: {
361→            data: {
362→              full_name: fullName,
363→            },
364→          },
365→        });
366→        if (signupError) {
367→          throw signupError;
368→        }
369→        if (data.user) {
370→          await supabase.from('profiles').upsert(
371→            {
372→              id: data.user.id,
373→              email,
374→              full_name: fullName,
375→            },
376→            { onConflict: 'id' },
377→          );
378→        }
379→        return true;
380→      } catch (signupCaught) {
381→        const message = signupCaught instanceof Error ? signupCaught.message : 'Inscription impossible';
382→        setError(message);
383→        return false;
384→      } finally {
385→        setLoading(false);
386→      }
387→    },
388→    [],
389→  );
390→
391→  /**
392→   * Ferme la session utilisateur.
393→   */
394→  const logout = useCallback(async (): Promise<void> => {
395→    if (!isSupabaseConfigured) {
396→      setUser(null);
397→      setProfile(null);
398→      if (typeof window !== 'undefined') {
399→        window.localStorage.removeItem(DEMO_AUTH_STORAGE_KEY);
400→        window.localStorage.removeItem(DEMO_PROFILE_STORAGE_KEY);
401→      }
402→      return;
403→    }
404→    setLoading(true);
405→    setError(null);
406→    const { error: logoutError } = await supabase.auth.signOut();
407→    if (logoutError) {
408→      setError(logoutError.message);
409→    }
410→    setLoading(false);
411→  }, []);
412→
413→  /**
414→   * Lance le flux de reset mot de passe Supabase.
415→   */
416→  const resetPassword = useCallback(async (email: string): Promise<boolean> => {
417→    if (!isSupabaseConfigured) {
418→      if (!email.trim()) {
419→        setError('Email requis.');
420→        return false;
421→      }
422→      setError('Mode demo: reset indisponible sans Supabase.');
423→      return true;
424→    }
425→    try {
426→      setError(null);
427→      const { error: resetError } = await supabase.auth.resetPasswordForEmail(email);
428→      if (resetError) {
429→        throw resetError;
430→      }
431→      return true;
432→    } catch (resetCaught) {
433→      const message = resetCaught instanceof Error ? resetCaught.message : 'Reset impossible';
434→      setError(message);
435→      return false;
436→    }
437→  }, []);
438→
439→  const clearError = useCallback(() => setError(null), []);
440→
441→  const value = useMemo<AuthContextValue>(
442→    () => ({
443→      user,
444→      profile,
445→      loading,
446→      error,
447→      login,
448→      signup,
449→      logout,
450→      resetPassword,
451→      clearError,
452→      refreshProfile,
453→      patchProfile,
454→    }),
455→    [clearError, error, loading, login, logout, patchProfile, profile, refreshProfile, resetPassword, signup, user],
456→  );
457→
458→  return <AuthContext.Provider value={value}>{children}</AuthContext.Provider>;
459→};
