  70→/**
  71→ * Hex color to RGB helper for jsPDF.
  72→ */
  73→const hexToRgb = (hex: string): [number, number, number] => {
  74→  const clean = hex.replace('#', '');
  75→  const r = parseInt(clean.substring(0, 2), 16) || 0;
  76→  const g = parseInt(clean.substring(2, 4), 16) || 0;
  77→  const b = parseInt(clean.substring(4, 6), 16) || 0;
  78→  return [r, g, b];
  79→};
