 89→          <circle cx={size / 2} cy={size / 2} r={radius} stroke={color} strokeWidth="6" fill="none"
 90→            strokeLinecap="round" strokeDasharray={circumference} strokeDashoffset={offset}
 91→            style={{ transition: 'stroke-dashoffset 1s ease-out' }} />
 92→        </svg>
